registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var size = t * 3.5 + 0.5;

    // Hue shifts from cyan-green toward blue-purple as trail ages
    var hue = 160 - t * 80;
    var sat = 80 + t * 20;
    var lit = 50 + t * 20;

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.strokeStyle = 'hsl(' + hue + ',' + sat + '%,' + lit + '%)';
    ctx.lineWidth = size;
    ctx.lineCap = 'round';
    ctx.shadowColor = 'hsl(' + hue + ',100%,70%)';
    ctx.shadowBlur = size * 3;

    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.stroke();
    ctx.restore();
  }

  // Glow dot at trail head (oldest visible)
  var head = trail.points[0];
  ctx.save();
  ctx.globalAlpha = 0.18;
  ctx.fillStyle = '#00ffcc';
  ctx.shadowColor = '#00ffcc';
  ctx.shadowBlur = 8;
  ctx.beginPath();
  ctx.arc(head.x, head.y, 1.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
})

