registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    for (var i = 0; i < 200; i++) {
      arr.push({
        x: Math.random() * 1600 - 800,
        y: Math.random() * 1200 - 600,
        z: Math.random() * 3 + 0.2,
        blink: Math.random() * Math.PI * 2,
        blinkSpeed: Math.random() * 0.03 + 0.005,
        size: Math.random() * 1.2 + 0.2,
        hue: Math.random() < 0.15 ? (Math.random() < 0.5 ? 200 : 280) : 0,
        sat: Math.random() < 0.15 ? (Math.random() * 40 + 60) : 0
      });
    }
    return arr;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = g._stars;
  var cx = W / 2;
  var cy = H / 2;

  ctx.save();

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Drift slowly with parallax based on depth
    s.x -= (g.vx * s.z * 0.18);
    s.y -= (g.vy * s.z * 0.18);

    // Wrap around a generous field
    var hw = W * 0.75;
    var hh = H * 0.75;
    if (s.x < cx - hw) s.x += hw * 2;
    if (s.x > cx + hw) s.x -= hw * 2;
    if (s.y < cy - hh) s.y += hh * 2;
    if (s.y > cy + hh) s.y -= hh * 2;

    // Twinkle
    s.blink += s.blinkSpeed;
    var twinkle = 0.5 + 0.5 * Math.sin(s.blink);
    var alpha = (0.3 + twinkle * 0.7) * (0.4 + s.z * 0.2);

    var screenX = s.x;
    var screenY = s.y;
    var radius = s.size * (0.6 + s.z * 0.3) * (0.8 + twinkle * 0.4);

    // Color: white/blue/purple tint
    var lightness = 70 + twinkle * 25;
    var colorStr;
    if (s.hue === 0) {
      colorStr = 'rgba(' +
        Math.round(200 + twinkle * 55) + ',' +
        Math.round(210 + twinkle * 45) + ',' +
        Math.round(230 + twinkle * 25) + ',' +
        alpha.toFixed(3) + ')';
    } else {
      // Colored star — use hsl
      colorStr = 'hsla(' + s.hue + ',' + s.sat + '%,' + lightness + '%,' + alpha.toFixed(3) + ')';
    }

    ctx.beginPath();
    ctx.arc(screenX, screenY, radius, 0, Math.PI * 2);
    ctx.fillStyle = colorStr;
    ctx.fill();

    // Subtle glow for brighter/deeper stars
    if (s.z > 2.2 && twinkle > 0.7) {
      var glowR = radius * 3.5;
      var grad = ctx.createRadialGradient(screenX, screenY, 0, screenX, screenY, glowR);
      var glowAlpha = (alpha * 0.25 * twinkle).toFixed(3);
      if (s.hue === 0) {
        grad.addColorStop(0, 'rgba(180,200,255,' + glowAlpha + ')');
      } else {
        grad.addColorStop(0, 'hsla(' + s.hue + ',80%,80%,' + glowAlpha + ')');
      }
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.beginPath();
      ctx.arc(screenX, screenY, glowR, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
    }
  }

  ctx.restore();
})

